#include <iostream>
#include <vector>

class FileHandlePool {
public:
    void add(int fd) {
        if (fd >= 0 && !contains(fd)) {
            fileHandles.push_back(fd);
        }
    }

    bool remove(int fd) {
        auto it = std::find(fileHandles.begin(), fileHandles.end(), fd);
        if (it != fileHandles.end()) {
            fileHandles.erase(it);
            return true;
        }
        return false;
    }

    void cleanup() {
        for (auto& fd : fileHandles) {
            close(fd);
        }
        fileHandles.clear();
    }

private:
    bool contains(int fd) const {
        return std::find(fileHandles.begin(), fileHandles.end(), fd) != fileHandles.end();
    }

    std::vector<int> fileHandles;
};

int main() {
    FileHandlePool pool;

    // Example usage
    int fd1 = 10, fd2 = 20;
    pool.add(fd1);
    pool.add(fd2);

    std::cout << "File handles: ";
    for (auto& fd : pool.fileHandles) {
        std::cout << fd << " ";
    }
    std::cout << std::endl;

    pool.remove(fd1);
    std::cout << "After removing fd1:" << std::endl;
    std::cout << "File handles: ";
    for (auto& fd : pool.fileHandles) {
        std::cout << fd << " ";
    }
    std::cout << std::endl;

    pool.cleanup();
    std::cout << "After cleanup:" << std::endl;
    std::cout << "File handles: ";
    for (auto& fd : pool.fileHandles) {
        std::cout << fd << " ";
    }
    std::cout << std::endl;

    return 0;
}